// Build a Telegram HTML message:
//   1. Per-order cards (━━━ separators with name / address / dishes)
//   2. 📊 今日订单表 — pivot matrix wrapped in <pre> (monospace,
//      so the endpoint's space-aligned columns render flush).
//   3. 备注 + 一行一项的食材采购清单.

const data = $input.first().json;

const esc = (s) => String(s ?? '无')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

const ingredientToBullets = (text) => {
  if (!text || text === '无') return '• 无';
  const out = text.split('；').map(s => `• ${s.trim()}`).filter(s => s !== '•');
  return out.length ? out.join('\n') : '• 无';
};

// Matrix is space-aligned monospace text. Wrap in <pre> so Telegram
// renders it in the code-block font (otherwise spaces collapse).
const fmtMatrix = (text) => {
  if (!text || text === '无') return '无';
  return `<pre>${esc(text)}</pre>`;
};

const lunchCount = data.lunch?.count ?? 0;
const dinnerCount = data.dinner?.count ?? 0;
const lunchOrders = esc(data.lunch?.ordersText ?? data.lunch?.summaryText);
const dinnerOrders = esc(data.dinner?.ordersText ?? data.dinner?.summaryText);
const lunchMatrix = fmtMatrix(data.lunch?.matrixText);
const dinnerMatrix = fmtMatrix(data.dinner?.matrixText);
const lunchIngredients = esc(ingredientToBullets(data.lunch?.ingredientText ?? data.ingredientText));
const dinnerIngredients = esc(ingredientToBullets(data.dinner?.ingredientText ?? data.ingredientText));
const notesText = esc(data.notesText);

const lines = [
  `🍳 <b>早安 BowlMama</b> — ${esc(data.date)}`,
  '',
  `🌞 <b>午餐</b> (${lunchCount} 单)`,
  '',
  lunchOrders,
  '',
  `🌙 <b>晚餐</b> (${dinnerCount} 单)`,
  '',
  dinnerOrders,
  '',
  '📊 <b>今日订单表</b>',
  '',
  '🌞 <b>午餐</b>',
  lunchMatrix,
  '',
  '🌙 <b>晚餐</b>',
  dinnerMatrix,
  '',
  '📝 <b>备注</b>',
  notesText,
  '',
  '🛒 <b>今日采购</b>',
  '',
  '🌞 <b>午餐</b>',
  lunchIngredients,
  '',
  '🌙 <b>晚餐</b>',
  dinnerIngredients,
  '',
  '—— Incredibowl 厨房系统',
];

return [{ json: { text: lines.join('\n'), _raw: data } }];

// Surface failures. Telegram returns 400 if chatId hasn't messaged the
// bot first, or 401 if token is wrong. Right now this only writes to
// the n8n execution log — swap for an email node if you want push alerts.
const err = $input.first().json;
console.error('[daily-prep-tg] Telegram send failed', JSON.stringify(err));
return [{ json: { error: err } }];
